class SessionManager {
    private final Map<String, AuthenticatedSession> activeSessions = new HashMap<>();

    public AuthenticatedSession createSession(String principal,
                                              Map<String, List<String>> attributes,
                                              SamlAssertion assertion) {
        if (principal == null || principal.trim().isEmpty()) {
            throw new SamlProcessingException("Cannot create session without principal");
        }

        String sessionId = UUID.randomUUID().toString();
        Instant now = Instant.now();

        Map<String, List<String>> immutableAttributes = new LinkedHashMap<>();
        for (Map.Entry<String, List<String>> entry : attributes.entrySet()) {
            immutableAttributes.put(entry.getKey(), Collections.unmodifiableList(new ArrayList<>(entry.getValue())));
        }

        AuthenticatedSession session = new AuthenticatedSession(
                sessionId,
                principal,
                Collections.unmodifiableMap(immutableAttributes),
                now,
                assertion.getNotOnOrAfter()
        );

        activeSessions.put(sessionId, session);
        return session;
    }

    public AuthenticatedSession getSession(String sessionId) {
        AuthenticatedSession session = activeSessions.get(sessionId);
        if (session == null) {
            return null;
        }
        if (session.getExpiresAt() != null && !Instant.now().isBefore(session.getExpiresAt())) {
            activeSessions.remove(sessionId);
            return null;
        }
        return session;
    }

    public void invalidateSession(String sessionId) {
        activeSessions.remove(sessionId);
    }
}

